function formatDateInTimeZone(date, timeZone) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(date);
  const map = Object.fromEntries(parts.map((part) => [part.type, part.value]));
  return `${map.year}-${map.month}-${map.day}`;
}

const cleaningDate = formatDateInTimeZone(new Date(), 'Asia/Ho_Chi_Minh');

return {
  json: {
    backendBaseUrl: 'http://host.docker.internal:3000/api/v1',
    internalToken: 'dev-internal-token',
    source: 'n8n-daily-generate',
    force: false,
    cleaningReasons: [
      'COMMON_AREA_DAILY',
      'CHECKOUT_ROOM',
      'PRE_CHECKIN_ROOM',
      'STAYOVER_ROOM',
    ],
    googleSpreadsheetId: 'PASTE_GOOGLE_SPREADSHEET_ID_HERE',
    todaySheetName: 'H\u00f4m nay',
    catalogSheetName: 'Danh m\u1ee5c',
    cleaningDate,
  },
};

const generation = $('Generate Cleaning Jobs').first().json.data ?? $('Generate Cleaning Jobs').first().json;
const sheetData = $('Get Daily Sheet Data').first().json.data ?? $('Get Daily Sheet Data').first().json;
const config = $('Build Generate Payload').first().json;
const sheetUrl = 'https://docs.google.com/spreadsheets/d/' + config.googleSpreadsheetId + '/edit';
const success = generation.success === true;
const title = success
  ? 'Danh s\u00e1ch v\u1ec7 sinh h\u00f4m nay \u0111\u00e3 s\u1eb5n s\u00e0ng'
  : 'T\u1ea1o danh s\u00e1ch v\u1ec7 sinh th\u1ea5t b\u1ea1i';
const cleaningDate = String(generation.cleaningDate ?? config.cleaningDate ?? '-').slice(0, 10);
const created = generation.created ?? 0;
const skipped = generation.skipped ?? 0;
const totalRows = sheetData.taskCount ?? 0;
const activeStaff = sheetData.staffCount ?? 0;
const esc = (value) => String(value ?? '-').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const text = [
  title,
  'Ng\u00e0y: ' + cleaningDate,
  'Task m\u1edbi: ' + created,
  'Task \u0111\u00e3 t\u1ed3n t\u1ea1i: ' + skipped,
  'D\u00f2ng tr\u00ean sheet: ' + totalRows,
  'Nh\u00e2n vi\u00ean kh\u1ea3 d\u1ee5ng: ' + activeStaff,
  'Google Sheet: ' + sheetUrl,
].join('\n');

const blocks = [
  {
    type: 'header',
    text: {
      type: 'plain_text',
      text: (success ? '\u{1F9F9} ' : '\u26A0\uFE0F ') + title,
      emoji: true,
    },
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: '*Ng\u00e0y v\u1ec7 sinh*\n' + esc(cleaningDate) },
      { type: 'mrkdwn', text: '*D\u00f2ng tr\u00ean sheet*\n' + esc(totalRows) },
      { type: 'mrkdwn', text: '*Task m\u1edbi*\n' + esc(created) },
      { type: 'mrkdwn', text: '*Task \u0111\u00e3 t\u1ed3n t\u1ea1i*\n' + esc(skipped) },
      { type: 'mrkdwn', text: '*Nh\u00e2n vi\u00ean kh\u1ea3 d\u1ee5ng*\n' + esc(activeStaff) },
      { type: 'mrkdwn', text: '*C\u01a1 s\u1edf*\n' + esc(generation.facilities ?? 0) },
    ],
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: [
        '*Chi ti\u1ebft c\u00f4ng vi\u1ec7c*',
        '\u2022 Khu v\u1ef1c chung: ' + esc(generation.commonAreaCreated ?? 0),
        '\u2022 Ph\u00f2ng checkout: ' + esc(generation.checkoutRoomCreated ?? 0),
        '\u2022 Ph\u00f2ng tr\u01b0\u1edbc check-in: ' + esc(generation.preCheckinRoomCreated ?? 0),
        '\u2022 Ph\u00f2ng l\u01b0u tr\u00fa: ' + esc(generation.stayoverRoomCreated ?? 0),
      ].join('\n'),
    },
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: '<' + sheetUrl + '|M\u1edf Google Sheet ph\u00e2n c\u00f4ng v\u1ec7 sinh>',
    },
  },
  {
    type: 'context',
    elements: [
      {
        type: 'mrkdwn',
        text: 'Workflow t\u1ef1 \u0111\u1ed9ng l\u00fac 00:05 \u2022 Sheet \u0111\u00e3 \u0111\u01b0\u1ee3c c\u1eadp nh\u1eadt \u0111\u1ec3 ph\u00e2n c\u00f4ng \u0111\u1ea7u ng\u00e0y',
      },
    ],
  },
];

return {
  json: {
    title,
    text,
    slackPayload: { text, blocks },
    response: generation,
    sheetUrl,
  },
};

const config = $('Build Generate Payload').first().json;
const sheets = $json.sheets ?? [];
const existingTitles = new Set(sheets.map((sheet) => sheet.properties?.title).filter(Boolean));
const requiredTitles = [config.todaySheetName, config.catalogSheetName];
const missingTitles = requiredTitles.filter((title) => !existingTitles.has(title));
const headersBySheet = {
  [config.todaySheetName]: [
    'task_id',
    'ng\u00e0y v\u1ec7 sinh',
    'c\u01a1 s\u1edf',
    'ph\u00f2ng / khu v\u1ef1c',
    'lo\u1ea1i ph\u00f2ng',
    'lo\u1ea1i c\u00f4ng vi\u1ec7c',
    'm\u1ed1c c\u1ea7n xong',
    'nh\u00e2n vi\u00ean ch\u00ednh',
    'nh\u00e2n vi\u00ean h\u1ed7 tr\u1ee3',
    'tr\u1ea1ng th\u00e1i',
    'gi\u1edd b\u1eaft \u0111\u1ea7u',
    'gi\u1edd k\u1ebft th\u00fac',
    'ng\u01b0\u1eddi gi\u00e1m s\u00e1t',
    'k\u1ebft qu\u1ea3 ki\u1ec3m tra',
    'ghi ch\u00fa hi\u1ec7n tr\u01b0\u1eddng',
    'ghi ch\u00fa h\u1ec7 th\u1ed1ng',
  ],
  [config.catalogSheetName]: ['staff_id', 'nh\u00e2n vi\u00ean', 't\u00ean ng\u1eafn'],
};

return {
  json: {
    missingTitles,
    hasMissingSheets: missingTitles.length > 0,
    requests: missingTitles.map((title) => ({ addSheet: { properties: { title } } })),
    headerData: missingTitles.map((title) => ({
      range: '\'' + title + '\'!A1',
      values: [headersBySheet[title]],
    })),
  },
};

const response = $json.data ?? $json;
const rows = response.taskRows ?? [];
return { json: { rows, hasRows: rows.length > 0 } };

const response = $json.data ?? $json;
const rows = response.staffRows ?? [];
return { json: { rows, hasRows: rows.length > 0 } };

const config = $('Build Generate Payload').first().json;
const sheets = $json.sheets ?? [];
const todaySheet = sheets.find((sheet) => sheet.properties?.title === config.todaySheetName);
const catalogSheet = sheets.find((sheet) => sheet.properties?.title === config.catalogSheetName);
const todaySheetId = todaySheet?.properties?.sheetId;
const catalogSheetId = catalogSheet?.properties?.sheetId;

if (todaySheetId === undefined || catalogSheetId === undefined) {
  throw new Error('Kh\u00f4ng t\u00ecm th\u1ea5y sheet c\u1ea7n thi\u1ebft sau b\u01b0\u1edbc kh\u1edfi t\u1ea1o');
}

const staffRange = '=\'' + config.catalogSheetName + '\'!$B$2:$B';
const makeRange = (sheetId, startColumnIndex, endColumnIndex, startRowIndex = 1, endRowIndex) => ({
  sheetId,
  startRowIndex,
  ...(endRowIndex === undefined ? {} : { endRowIndex }),
  startColumnIndex,
  endColumnIndex,
});
const dropdownRule = (condition, inputMessage) => ({
  condition,
  inputMessage,
  strict: false,
  showCustomUi: true,
});
const headerFormat = {
  backgroundColor: { red: 0.11, green: 0.24, blue: 0.36 },
  horizontalAlignment: 'CENTER',
  verticalAlignment: 'MIDDLE',
  wrapStrategy: 'WRAP',
  textFormat: {
    foregroundColor: { red: 1, green: 1, blue: 1 },
    bold: true,
  },
};
const staffValidation = dropdownRule(
  { type: 'ONE_OF_RANGE', values: [{ userEnteredValue: staffRange }] },
  'Ch\u1ecdn nh\u00e2n vi\u00ean t\u1eeb danh m\u1ee5c hi\u1ec7n c\u00f3',
);
const statusValidation = dropdownRule(
  {
    type: 'ONE_OF_LIST',
    values: [
      'Ch\u01b0a b\u1eaft \u0111\u1ea7u',
      '\u0110ang d\u1ecdn',
      'T\u1ea1m d\u1eebng',
      '\u0110\u00e3 xong',
      '\u0110\u00e3 ki\u1ec3m tra',
      'M\u1edf l\u1ea1i',
      '\u0110\u00e3 h\u1ee7y',
    ].map((value) => ({ userEnteredValue: value })),
  },
  'Ch\u1ecdn tr\u1ea1ng th\u00e1i task',
);
const inspectionValidation = dropdownRule(
  {
    type: 'ONE_OF_LIST',
    values: ['\u0110\u1ea1t', 'C\u1ea7n l\u00e0m l\u1ea1i'].map((value) => ({ userEnteredValue: value })),
  },
  'Ch\u1ecdn k\u1ebft qu\u1ea3 ki\u1ec3m tra',
);
const widths = [
  [0, 1, 80],
  [1, 2, 115],
  [2, 3, 180],
  [3, 4, 150],
  [4, 5, 130],
  [5, 6, 190],
  [6, 7, 165],
  [7, 9, 185],
  [9, 10, 145],
  [10, 12, 110],
  [12, 13, 185],
  [13, 14, 155],
  [14, 15, 240],
  [15, 16, 260],
];
const catalogWidths = [
  [0, 1, 90],
  [1, 2, 220],
  [2, 3, 150],
];
const existingStatusFormulas = new Set(
  (todaySheet.conditionalFormats ?? [])
    .map((rule) => rule.booleanRule?.condition)
    .filter((condition) => condition?.type === 'CUSTOM_FORMULA')
    .flatMap((condition) => condition.values ?? [])
    .map((value) => value.userEnteredValue)
    .filter(Boolean),
);
const statusRules = [
  {
    formula: '=$J2="Ch\u01b0a b\u1eaft \u0111\u1ea7u"',
    backgroundColor: { red: 0.92, green: 0.94, blue: 0.96 },
  },
  {
    formula: '=$J2="\u0110ang d\u1ecdn"',
    backgroundColor: { red: 1, green: 0.95, blue: 0.72 },
  },
  {
    formula: '=$J2="T\u1ea1m d\u1eebng"',
    backgroundColor: { red: 1, green: 0.88, blue: 0.72 },
  },
  {
    formula: '=$J2="\u0110\u00e3 xong"',
    backgroundColor: { red: 0.82, green: 0.93, blue: 0.84 },
  },
  {
    formula: '=$J2="\u0110\u00e3 ki\u1ec3m tra"',
    backgroundColor: { red: 0.8, green: 0.88, blue: 1 },
  },
  {
    formula: '=$J2="M\u1edf l\u1ea1i"',
    backgroundColor: { red: 1, green: 0.82, blue: 0.82 },
  },
  {
    formula: '=$J2="\u0110\u00e3 h\u1ee7y"',
    backgroundColor: { red: 0.88, green: 0.88, blue: 0.88 },
  },
];

const typedColumns = new Set(
  (todaySheet.tables ?? []).flatMap((table) => {
    const startColumnIndex = table.range?.startColumnIndex ?? 0;
    return (table.columnProperties ?? [])
      .filter((column) => column.columnType && column.columnType !== 'COLUMN_TYPE_UNSPECIFIED')
      .map((column) => startColumnIndex + column.columnIndex);
  }),
);
const isTypedRange = (startColumnIndex, endColumnIndex) => {
  for (let columnIndex = startColumnIndex; columnIndex < endColumnIndex; columnIndex += 1) {
    if (typedColumns.has(columnIndex)) return true;
  }
  return false;
};
const validationRequests = [
  [7, 8, staffValidation],
  [8, 9, staffValidation],
  [9, 10, statusValidation],
  [12, 13, staffValidation],
  [13, 14, inspectionValidation],
]
  .filter(([startColumnIndex, endColumnIndex]) => !isTypedRange(startColumnIndex, endColumnIndex))
  .map(([startColumnIndex, endColumnIndex, rule]) => ({
    setDataValidation: {
      range: makeRange(todaySheetId, startColumnIndex, endColumnIndex),
      rule,
    },
  }));

const requests = [
  ...validationRequests,
  ...(!isTypedRange(10, 12)
    ? [
        {
          repeatCell: {
            range: makeRange(todaySheetId, 10, 12),
            cell: { userEnteredFormat: { numberFormat: { type: 'TIME', pattern: 'hh:mm' } } },
            fields: 'userEnteredFormat.numberFormat',
          },
        },
      ]
    : []),
  {
    repeatCell: {
      range: { sheetId: todaySheetId, startRowIndex: 0, endRowIndex: 1 },
      cell: { userEnteredFormat: headerFormat },
      fields: 'userEnteredFormat(backgroundColor,textFormat,horizontalAlignment,verticalAlignment,wrapStrategy)',
    },
  },
  {
    repeatCell: {
      range: { sheetId: catalogSheetId, startRowIndex: 0, endRowIndex: 1 },
      cell: { userEnteredFormat: headerFormat },
      fields: 'userEnteredFormat(backgroundColor,textFormat,horizontalAlignment,verticalAlignment,wrapStrategy)',
    },
  },
  {
    updateSheetProperties: {
      properties: { sheetId: todaySheetId, gridProperties: { frozenRowCount: 1 } },
      fields: 'gridProperties.frozenRowCount',
    },
  },
  {
    updateSheetProperties: {
      properties: { sheetId: catalogSheetId, gridProperties: { frozenRowCount: 1 } },
      fields: 'gridProperties.frozenRowCount',
    },
  },
  ...(todaySheet.tables?.length
    ? []
    : [
        {
          setBasicFilter: {
            filter: {
              range: { sheetId: todaySheetId, startRowIndex: 0, startColumnIndex: 0, endColumnIndex: 16 },
            },
          },
        },
      ]),
  ...(catalogSheet.tables?.length
    ? []
    : [
        {
          setBasicFilter: {
            filter: {
              range: { sheetId: catalogSheetId, startRowIndex: 0, startColumnIndex: 0, endColumnIndex: 3 },
            },
          },
        },
      ]),
  {
    repeatCell: {
      range: makeRange(todaySheetId, 14, 16),
      cell: { userEnteredFormat: { wrapStrategy: 'WRAP', verticalAlignment: 'TOP' } },
      fields: 'userEnteredFormat(wrapStrategy,verticalAlignment)',
    },
  },
  ...widths.map(([startIndex, endIndex, pixelSize]) => ({
    updateDimensionProperties: {
      range: { sheetId: todaySheetId, dimension: 'COLUMNS', startIndex, endIndex },
      properties: { pixelSize },
      fields: 'pixelSize',
    },
  })),
  ...catalogWidths.map(([startIndex, endIndex, pixelSize]) => ({
    updateDimensionProperties: {
      range: { sheetId: catalogSheetId, dimension: 'COLUMNS', startIndex, endIndex },
      properties: { pixelSize },
      fields: 'pixelSize',
    },
  })),
  ...statusRules
    .filter((rule) => !existingStatusFormulas.has(rule.formula))
    .map((rule) => ({
      addConditionalFormatRule: {
        rule: {
          ranges: [makeRange(todaySheetId, 9, 10)],
          booleanRule: {
            condition: {
              type: 'CUSTOM_FORMULA',
              values: [{ userEnteredValue: rule.formula }],
            },
            format: {
              backgroundColor: rule.backgroundColor,
              textFormat: { bold: true },
            },
          },
        },
        index: 0,
      },
    })),
];

return { json: { requests } };
